const b = $input.item.json.body || $input.item.json;
const fileId = b.drive_file_id || '';
const driveUrl = fileId
  ? `https://drive.usercontent.google.com/download?id=${fileId}&export=download&confirm=t`
  : (b.drive_url || '');
return [{ json: {
  headline:          b.headline          || '',
  facebook_caption:  b.facebook_caption  || b.headline || '',
  linkedin_caption:  b.linkedin_caption  || b.headline || '',
  instagram_caption: b.instagram_caption || b.facebook_caption || b.headline || '',
  tiktok_caption:    b.tiktok_caption    || b.headline || '',
  drive_file_id:     fileId,
  drive_url:         driveUrl
} }];

const data = $input.item.json;

function clean(text) {
  if (!text) return '';
  // strip emojis
  let res = text.replace(/[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F1E6}-\u{1F1FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}]/gu, '');
  // strip problematic chars but KEEP # (hashtags) and _ (used in hashtags)
  res = res.replace(/[\/\"*^%$@!~]/g, '');
  return res.replace(/\s+/g, ' ').trim();
}

return [{ json: {
  ...data,
  facebook_caption:  clean(data.facebook_caption),
  linkedin_caption:  clean(data.linkedin_caption),
  instagram_caption: clean(data.instagram_caption),
  tiktok_caption:    clean(data.tiktok_caption)
}}];

const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
const binary = await this.helpers.prepareBinaryData(binaryData, 'physics_post.png', 'image/png');
return [{
  json: {
    facebook_caption: $('Clean Captions').item.json.facebook_caption,
    linkedin_caption: $('Clean Captions').item.json.linkedin_caption
  },
  binary: { data: binary }
}];

const rows = $input.item.json?.values || [];
// Columns: 0=ID,1=Topic,2=CustomHeadline,3=Status,4=CaptionsJSON,5=Headline,6=DriveFileId,7=DriveUrl,8=FBPostId,9=LIPostId,10=blank,11=PublishedAt,12=ReadyAt
const ready = rows
  .map((r, i) => ({
    rowIndex: i + 2,
    status: (r[3] || '').toUpperCase().trim(),
    captionsJson: r[4] || '',
    headline: r[5] || '',
    driveFileId: r[6] || '',
    driveUrl: r[7] || ''
  }))
  .filter(r => r.status === 'READY' && r.driveFileId);
if (ready.length === 0) {
  throw new Error('NO_READY_ROWS: No READY rows found in Image Post Queue.');
}
const first = ready[0];
let captions = {};
try { captions = JSON.parse(first.captionsJson); } catch (e) {}
return [{ json: {
  rowIndex:          first.rowIndex,
  headline:          first.headline,
  facebook_caption:  captions.facebook  || first.headline || '',
  linkedin_caption:  captions.linkedin  || first.headline || '',
  instagram_caption: captions.instagram || captions.facebook || first.headline || '',
  tiktok_caption:    captions.tiktok    || first.headline || '',
  drive_file_id:     first.driveFileId,
  drive_url:         first.driveUrl
} }];

let rowIndex = null, headline = '', driveFileId = '', driveUrl = '';
try {
  const d = $('Find First READY Row').item.json;
  rowIndex = d.rowIndex; headline = d.headline; driveFileId = d.drive_file_id; driveUrl = d.drive_url;
} catch (e) {}
return [{ json: { hasRow: !!rowIndex, rowIndex, headline, driveFileId, driveUrl } }];

const { execSync } = require('child_process');
const fs = require('fs');
const https = require('https');
const path = require('path');

const ts = Date.now();
const binId = $input.item.binary.data.id;
const filePath = '/home/node/.n8n/.n8n/storage/' + binId.replace('filesystem-v2:', '');
const imgBuf = fs.readFileSync(filePath);

const imgPath_n8n    = '/data/ffmpeg/input/qpc_reel_' + ts + '.jpg';
const imgPath_ffmpeg = '/ffmpeg/input/qpc_reel_' + ts + '.jpg';
const outPath_n8n    = '/data/ffmpeg/output/qpc_reel_' + ts + '.mp4';
const outPath_ffmpeg = '/ffmpeg/output/qpc_reel_' + ts + '.mp4';

fs.writeFileSync(imgPath_n8n, imgBuf);

const bgmDir = '/ffmpeg/config/bgm_aperture';
const bgmRaw = execSync('docker exec phys_ffmpeg_runner bash -c "ls ' + bgmDir + '/*.mp3 2>/dev/null"', { encoding: 'utf-8' }).trim();
const bgmList = bgmRaw.split('\n').filter(Boolean);
if (!bgmList.length) throw new Error('No BGM files found at ' + bgmDir);
const bgm = bgmList[Math.floor(Math.random() * bgmList.length)];

const scale = 'scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:color=black';
const ffCmd = 'ffmpeg -y -loop 1 -i \'' + imgPath_ffmpeg + '\' -i \'' + bgm + '\' -c:v libx264 -t 20 -pix_fmt yuv420p -vf "' + scale + '" -c:a aac -b:a 128k -movflags +faststart \'' + outPath_ffmpeg + '\'';
execSync('docker exec phys_ffmpeg_runner bash -c ' + JSON.stringify(ffCmd), { timeout: 120000, encoding: 'utf-8' });

try { fs.unlinkSync(imgPath_n8n); } catch(e) {}

// Upload video to PostForMe media endpoint
const apiKey = $env.POSTFORME_API_KEY;
const uploadUrlRes = await new Promise(function(resolve, reject) {
  const req = https.request({
    hostname: 'api.postforme.dev', path: '/v1/media/create-upload-url', method: 'POST',
    headers: { 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json', 'Content-Length': 0 }
  }, function(res) {
    let d = ''; res.on('data', function(c){ d+=c; }); res.on('end', function(){ try{ resolve(JSON.parse(d)); }catch(e){ reject(new Error('Non-JSON: '+d.slice(0,200))); } });
  });
  req.on('error', reject); req.end();
});
if (!uploadUrlRes.upload_url) throw new Error('PostForMe upload URL failed: ' + JSON.stringify(uploadUrlRes));

const videoBuf = fs.readFileSync(outPath_n8n);

// PUT video to signed URL
const uploadHost = new URL(uploadUrlRes.upload_url).hostname;
const uploadPath = uploadUrlRes.upload_url.replace('https://' + uploadHost, '');
await new Promise(function(resolve, reject) {
  const req = https.request({
    hostname: uploadHost, path: uploadPath, method: 'PUT',
    headers: { 'Content-Type': 'video/mp4', 'Content-Length': videoBuf.length }
  }, function(res) { res.resume(); res.on('end', resolve); });
  req.on('error', reject); req.write(videoBuf); req.end();
});

const postforme_media_url = uploadUrlRes.media_url;
try { fs.unlinkSync(outPath_n8n); } catch(e) {}

const binary = await this.helpers.prepareBinaryData(videoBuf, 'qpc_reel_' + ts + '.mp4', 'video/mp4');

return { json: Object.assign({}, $input.item.json, { reelJobId: ts, bgmUsed: path.basename(bgm), postforme_media_url: postforme_media_url }), binary: { data: binary } };

const https = require('https');
const data = $input.item.json;

const apiKey = $env.POSTFORME_API_KEY;
const mediaUrl = data.postforme_media_url;
if (!apiKey) throw new Error('POSTFORME_API_KEY not set');
if (!mediaUrl) throw new Error('postforme_media_url not found — upload step failed');

const caption = ((data.instagram_caption || '') + '\n\n' + (data.tiktok_caption || '')).slice(0, 2190);

const postBody = JSON.stringify({
  caption: caption,
  social_accounts: [$env.POSTFORME_PHYSICS_IG_ACCOUNT_ID, $env.POSTFORME_PHYSICS_TIKTOK_ACCOUNT_ID],
  media: [{ url: mediaUrl }]
});

const result = await new Promise(function(resolve, reject) {
  const buf = Buffer.from(postBody);
  const req = https.request({
    hostname: 'api.postforme.dev', path: '/v1/social-posts', method: 'POST',
    headers: { 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json', 'Content-Length': buf.length }
  }, function(res) {
    let d = '';
    res.on('data', function(c) { d += c; });
    res.on('end', function() { try { resolve(JSON.parse(d)); } catch(e) { reject(new Error('Non-JSON: ' + d.slice(0, 200))); } });
  });
  req.on('error', reject);
  req.write(buf);
  req.end();
});

if (result.error) throw new Error('PostForMe error: ' + JSON.stringify(result));

return { json: { postforme_result: JSON.stringify(result), mediaUrl: mediaUrl } };

