const https = require('https');
const data  = $input.item.json;

const apiKey  = $env.POSTFORME_API_KEY;
const driveId = data.id || $('Upload Reel to Drive').item.json.id;
if (!apiKey)  throw new Error('POSTFORME_API_KEY not set');
